-- =============================================
-- 武将槽位基础属性表 (基于 APK 数据反推)
-- 属性体系: genAtt(攻击) genDef(防御) genFor(武力) genLeader(统帅)
-- 成长公式: attr = base + growth × (level - 1)
-- =============================================

CREATE TABLE IF NOT EXISTS `general_slot` (
  `id` INT AUTO_INCREMENT,
  `quality_code` VARCHAR(16) NOT NULL COMMENT '品质: orange/purple/red/blue/green/white',
  `troop_type` VARCHAR(8) NOT NULL COMMENT '兵种: 步/骑/弓',
  `type` VARCHAR(16) NOT NULL COMMENT '类型: 统帅/猛将/智将',
  `slot_index` INT DEFAULT 0 COMMENT '品质内序号',
  `base_attack` INT DEFAULT 0 COMMENT '基础攻击(genAtt)',
  `base_defense` INT DEFAULT 0 COMMENT '基础防御(genDef)',
  `base_valor` INT DEFAULT 0 COMMENT '基础武力(genFor)',
  `base_command` INT DEFAULT 0 COMMENT '基础统帅(genLeader)',
  `base_dodge` DOUBLE DEFAULT 0 COMMENT '基础闪避',
  `base_mobility` INT DEFAULT 0 COMMENT '基础速度',
  `base_power` INT DEFAULT 0 COMMENT '基础战力',
  `growth_attack` DOUBLE DEFAULT 0 COMMENT '攻击成长/级(genAttGrow)',
  `growth_defense` DOUBLE DEFAULT 0 COMMENT '防御成长/级(genDefGrow)',
  `growth_valor` DOUBLE DEFAULT 0 COMMENT '武力成长/级',
  `growth_command` DOUBLE DEFAULT 0 COMMENT '统帅成长/级',
  `base_tactics_trigger_bonus` INT DEFAULT 0 COMMENT '兵法发动概率基础加成(%)',
  `sort_order` INT DEFAULT 0,
  `is_virtual` TINYINT(1) DEFAULT 0 COMMENT '是否虚构武将',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='武将槽位基础属性(APK数据反推)';

-- 清空旧数据后重建
